template_code:
Type Noeud = Enregistrement
Debut
    valeur  : Entier;
    suivant : ^Noeud;
Fin;

Algorithme Detection_Milieu_Liste;
Var
    tete, lent, rapide, liste[1000] : ^Noeud;
    i, N, position_milieu           : Entier;
    Val[1000], index[1000]          : Entier;
Debut
    Lire(N);

    Pour i := 0 a N - 1 Faire
        Lire(Val[i]);
    FinPour

    Pour i := 0 a N - 1 Faire
        Lire(index[i]);
    FinPour

    // 1) Creation des noeuds
    Pour i := 0 a N - 1 Faire
        liste[i] := allouer(Taille(Noeud));
        liste[i]->valeur := Val[i];
    FinPour

    // 2) Etablissement des liens
    Pour i := 0 a N - 1 Faire
        Si index[i] = -1 Alors
            liste[i]->suivant := NIL;
        Sinon
            liste[i]->suivant := liste[index[i]];
        FinSi;
    FinPour

    tete := liste[0];

    // 3) Milieu (lièvre/tortue)
    Si tete = NIL Alors
        Ecrire("Liste vide");
    Sinon
        lent := tete;
        rapide := tete;
        position_milieu := 1;

        TantQue rapide <> NIL ET rapide->suivant <> NIL Faire
            lent := lent->suivant;
            rapide := rapide->suivant->suivant;
            position_milieu := position_milieu + 1;
        FinTantQue

        Ecrire(lent->valeur, " ", position_milieu);
    FinSi
Fin.
